### Backend (Node.js + Express)

First, ensure you have Node.js installed. Then, create a new directory for your project and initialize it:

```bash
mkdir room-management-system
cd room-management-system
npm init -y
```

Install the necessary dependencies:

```bash
npm install express mongoose body-parser cors
```

Create a file named `server.js`:

```javascript
const express = require('express');
const mongoose = require('mongoose');
const bodyParser = require('body-parser');
const cors = require('cors');

const app = express();

// Middleware
app.use(bodyParser.json());
app.use(cors());

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/roommanagement', {
    useNewUrlParser: true,
    useUnifiedTopology: true
}).then(() => console.log('MongoDB connected'))
  .catch(err => console.error('MongoDB connection error:', err));

// Room Schema
const RoomSchema = new mongoose.Schema({
    name: String,
    capacity: Number,
    isAvailable: Boolean
});

const Room = mongoose.model('Room', RoomSchema);

// Routes
app.get('/api/rooms', async (req, res) => {
    const rooms = await Room.find();
    res.send(rooms);
});

app.post('/api/rooms', async (req, res) => {
    const room = new Room({
        name: req.body.name,
        capacity: req.body.capacity,
        isAvailable: true
    });
    await room.save();
    res.send(room);
});

app.put('/api/rooms/:id', async (req, res) => {
    const room = await Room.findByIdAndUpdate(req.params.id, {
        name: req.body.name,
        capacity: req.body.capacity,
        isAvailable: req.body.isAvailable
    }, { new: true });
    res.send(room);
});

app.delete('/api/rooms/:id', async (req, res) => {
    await Room.findByIdAndDelete(req.params.id);
    res.send({ message: 'Room deleted' });
});

// Start server
const PORT = process.env.PORT || 5000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

